sql:
SELECT variant_id, chromosome, position
FROM variant_data
WHERE chromosome = '1';

external_knowledge:
- In genetics, a variant can refer to any change in the DNA sequence of an organism; 
- A phenotype is the physical and behavioral characteristics of an organism that result from the interaction of its genotype and the environment; 
- The role of 'admin' typically signifies an administrator with elevated privileges in a system or database;
- The `NTH_VALUE` function is used to return a value from a specific row within a result set, based on an ordering.

sql:
SELECT source_name
FROM variant_sources
WHERE last_updated > '2022-01-01';

SELECT data_types, COUNT(*) AS type_count
FROM variant_data
GROUP BY data_types;

SELECT source_name, last_updated
FROM variant_sources
ORDER BY last_updated DESC;

SELECT DISTINCT u.user_name
FROM users u
JOIN variant_history vh ON u.user_id = vh.changed_by;

SELECT chromosome
  FROM variant_data
  WHERE variant_id = 1;

SELECT COUNT(variant_id) AS variant_count
  FROM variant_phenotype_links
  WHERE phenotype_id = 1;

SELECT source_id, source_name, version, description, last_updated
FROM variant_sources
WHERE source_id = 0;

SELECT last_updated
  FROM variant_sources
  ORDER BY last_updated DESC;
